1	/**
2	 * Animator — custom Oculus API routes.
3	 *
4	 * Contributes:
5	 * - GET /api/animator/sessions — enriched session list with role, writ title, token usage
6	 * - GET /api/animator/session-transcript — session transcript and status
7	 * - GET /api/animator/session-stream — SSE stream of real-time session chunks
8	 *
9	 * Does NOT import from @shardworks/oculus-apparatus to avoid a circular
10	 * package dependency. The route shape is compatible with RouteContribution
11	 * from the Oculus types.
12	 */
13	
14	import type { Context } from 'hono';
15	import { streamSSE } from 'hono/streaming';
16	import { guild } from '@shardworks/nexus-core';
17	import type { StacksApi, WhereCondition } from '@shardworks/stacks-apparatus';
18	import type { SessionDoc, AnimatorApi } from './types.ts';
19	
20	/** Minimal inline type for transcript documents (avoids a full type import). */
21	interface TranscriptEntry {
22	  id: string;
23	  messages: Record<string, unknown>[];
24	  [key: string]: unknown;
25	}
26	
27	/** Minimal inline type for writ documents (avoids importing from clerk). */
28	interface WritEntry {
29	  id: string;
30	  title: string;
31	  [key: string]: unknown;
32	}
33	
34	export const animatorRoutes = [
35	  {
36	    method: 'GET',
37	    path: '/api/animator/status',
38	    handler: async (c: Context) => {
39	      // Read the back-off status doc through the Animator apparatus so
40	      // consumers (Oculus banner, external monitoring) see exactly what
41	      // the internal machine sees. Running on a fresh install returns
42	      // the default running shape — never a null body.
43	      const g = guild();
44	      const animator = g.apparatus<AnimatorApi>('animator');
45	      const status = await animator.getStatus();
46	      return c.json(status);
47	    },
48	  },
49	  {
50	    method: 'GET',
51	    path: '/api/animator/sessions',
52	    handler: async (c: Context) => {
53	      const status = c.req.query('status');
54	      const from = c.req.query('from');
55	      const to = c.req.query('to');
56	      const limitStr = c.req.query('limit');
57	      const limit = limitStr ? parseInt(limitStr, 10) : 50;
58	
59	      const g = guild();
60	      const stacks = g.apparatus<StacksApi>('stacks');
61	      const sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
62	
63	      const where: WhereCondition[] = [];
64	      if (status) where.push(['status', '=', status]);
65	      if (from) where.push(['startedAt', '>=', from]);
66	      if (to) where.push(['startedAt', '<=', to]);
67	
68	      const sessions = await sessionsBook.find({
69	        where: where.length > 0 ? where : undefined,
70	        orderBy: ['startedAt', 'desc'],
71	        limit: Number.isFinite(limit) ? limit : 50,
72	      });
73	
74	      // Collect unique writIds for batch resolution
75	      const writIds = new Set<string>();
76	      for (const s of sessions) {
77	        const writId = (s.metadata as Record<string, unknown> | undefined)?.writId;
78	        if (typeof writId === 'string') writIds.add(writId);
79	      }
80	
81	      // Resolve writ titles gracefully — if clerk book is unavailable, skip
82	      const writTitles = new Map<string, string>();
83	      if (writIds.size > 0) {
84	        try {
85	          const writsBook = stacks.readBook<WritEntry>('clerk', 'writs');
86	          await Promise.all(
87	            [...writIds].map(async (id) => {
88	              try {
89	                const writ = await writsBook.get(id);
90	                if (writ) writTitles.set(id, writ.title);
91	              } catch {
92	                // Individual writ lookup failure — skip gracefully
93	              }
94	            }),
95	          );
96	        } catch {
97	          // Clerk book unavailable — all writTitles remain undefined
98	        }
99	      }
100	
101	      const entries = sessions.map((s) => {
102	        const meta = s.metadata as Record<string, unknown> | undefined;
103	        const role = typeof meta?.role === 'string' ? meta.role : undefined;
104	        const writId = typeof meta?.writId === 'string' ? meta.writId : undefined;
105	
106	        return {
107	          id: s.id,
108	          status: s.status,
109	          provider: s.provider,
110	          startedAt: s.startedAt,
111	          endedAt: s.endedAt,
112	          durationMs: s.durationMs,
113	          exitCode: s.exitCode,
114	          costUsd: s.costUsd,
115	          role,
116	          writId,
117	          writTitle: writId ? writTitles.get(writId) : undefined,
118	          tokenUsage: s.tokenUsage,
119	        };
120	      });
121	
122	      return c.json(entries);
123	    },
124	  },
125	  {
126	    method: 'GET',
127	    path: '/api/animator/session-transcript',
128	    handler: async (c: Context) => {
129	      const sessionId = c.req.query('sessionId');
130	
131	      if (!sessionId) {
132	        return c.json({ error: 'sessionId is required' }, 400);
133	      }
134	
135	      const g = guild();
136	      const stacks = g.apparatus<StacksApi>('stacks');
137	
138	      const sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
