/**
 * Operational state stored in the Animator's 'state' book.
 * Single well-known document with id 'guild-heartbeat'.
 */
export interface GuildStateDoc {
  id: string;
  /** ISO timestamp of the last guild self-heartbeat. */
  guildAliveAt: string;
  /** Index signature required by BookEntry. */
  [key: string]: unknown;
}

// ── Animator status doc (rate-limit back-off) ────────────────────────

/**
 * Reason for the Animator's current pause state. Extensible — today only
 * `'rate-limit'` is produced, but the field is open so future operator-
 * triggered pause can reuse the same doc shape without a schema bump.
 */
export type AnimatorPauseReason = 'rate-limit';

/**
 * Operational state stored in the Animator's 'status' book.
 *
 * Single well-known document with id 'current'. Tracks whether the
 * anima provider is currently rate-limited, when the current pause
 * window ends, and the exponential back-off level that will be applied
 * to the next pause.
 *
 * Consumers (Spider's crawl gate, the Oculus banner, the
 * `animator-status` CLI tool) dispatch sessions only when:
 *   state === 'running' OR pausedUntil <= now
 * The combined check tolerates the "stale running" edge cases — a daemon
 * restart leaves the doc in its last persisted state; the first
 * successful dispatch naturally flips it back to `'running'` (D24).
 */
export interface AnimatorStatusDoc {
  id: string;
  /** Current pause state. `'running'` means sessions dispatch normally. */
  state: 'running' | 'paused';

