1	/**
2	 * Tests for rate-limit signature detection in the claude-code provider.
3	 *
4	 * Covers the three-branch cascade declared by decision D5:
5	 *   1. NDJSON `result` / error message inspection (first-wins)
6	 *   2. Stderr pattern match
7	 *   3. Distinguished exit code mapping
8	 *
9	 * Also verifies the cascade ordering inside resolveTerminalStatus() —
10	 * the babysitter's one-stop seat for translating a StreamJsonResult and
11	 * optional status override into the payload sent to session-record.
12	 */
13	
14	import { describe, it } from 'node:test';
15	import assert from 'node:assert/strict';
16	
17	import {
18	  detectRateLimitFromNdjson,
19	  detectRateLimitFromStderr,
20	  detectRateLimitFromExitCode,
21	  parseStreamJsonMessage,
22	  RATE_LIMIT_EXIT_CODE,
23	  type StreamJsonResult,
24	} from './index.ts';
25	import { resolveTerminalStatus } from './babysitter.ts';
26	import type { SessionTerminationTag } from '@shardworks/animator-apparatus';
27	
28	function freshAcc(): {
29	  transcript: Record<string, unknown>[];
30	  costUsd?: number;
31	  tokenUsage?: StreamJsonResult['tokenUsage'];
32	  providerSessionId?: string;
33	  terminationTag?: SessionTerminationTag;
34	} {
35	  return { transcript: [] };
36	}
37	
38	// ── NDJSON detection ────────────────────────────────────────────────
39	
40	describe('detectRateLimitFromNdjson()', () => {
41	  it('tags messages with a rate_limit subtype', () => {
42	    const tag = detectRateLimitFromNdjson({ type: 'result', subtype: 'rate_limit_error' });
43	    assert.ok(tag);
44	    assert.equal(tag!.kind, 'rate-limit');
45	    assert.equal(tag!.source, 'ndjson-result');
46	    assert.match(tag!.detail ?? '', /rate_limit_error/);
47	  });
48	
49	  it('tags is_error messages whose error text matches the pattern', () => {
50	    const tag = detectRateLimitFromNdjson({
51	      is_error: true,
52	      error: 'HTTP 429: rate limit exceeded',
53	    });
54	    assert.ok(tag);
55	    assert.equal(tag!.source, 'ndjson-result');
56	  });
57	
58	  it('tags result messages whose result text mentions rate limit', () => {
59	    const tag = detectRateLimitFromNdjson({
60	      type: 'result',
61	      result: 'Error: Rate limit exceeded. Please try again later.',
62	    });
63	    assert.ok(tag);
64	    assert.equal(tag!.source, 'ndjson-result');
65	  });
66	
67	  it('returns null on ordinary assistant messages', () => {
68	    const tag = detectRateLimitFromNdjson({
69	      type: 'assistant',
70	      message: { content: [{ type: 'text', text: 'Hello world' }] },
71	    });
72	    assert.equal(tag, null);
73	  });
74	
75	  it('returns null on a result message without matching text', () => {
76	    const tag = detectRateLimitFromNdjson({
77	      type: 'result',
78	      result: 'Done!',
79	      total_cost_usd: 0.01,
80	    });
81	    assert.equal(tag, null);
82	  });
83	});
84	
85	// ── stderr detection ────────────────────────────────────────────────
86	
87	describe('detectRateLimitFromStderr()', () => {
88	  it('matches "rate limit" phrasing case-insensitively', () => {
89	    const tag = detectRateLimitFromStderr('Error: Rate Limit reached, retry later.\n');
90	    assert.ok(tag);
91	    assert.equal(tag!.source, 'stderr-pattern');
92	  });
93	
94	  it('matches 429 status code', () => {
95	    const tag = detectRateLimitFromStderr('HTTP/1.1 429 Too Many Requests\n');
96	    assert.ok(tag);
97	  });
98	
99	  it('matches "usage limit" phrasing', () => {
100	    const tag = detectRateLimitFromStderr('Your usage limit has been reached for today.\n');
101	    assert.ok(tag);
102	  });
103	
104	  it('returns null on ordinary stderr', () => {
105	    const tag = detectRateLimitFromStderr('[babysitter] MCP proxy server listening on port 12345\n');
106	    assert.equal(tag, null);
107	  });
108	
109	  it('bounds the detail excerpt to 200 characters', () => {
110	    const longLine = 'rate limit exceeded: ' + 'x'.repeat(500);
111	    const tag = detectRateLimitFromStderr(longLine);
112	    assert.ok(tag);
113	    assert.ok((tag!.detail ?? '').length <= 200);
114	  });
115	});
116	
117	// ── exit code detection ────────────────────────────────────────────
118	
119	describe('detectRateLimitFromExitCode()', () => {
120	  it('tags the distinguished exit code', () => {
121	    const tag = detectRateLimitFromExitCode(RATE_LIMIT_EXIT_CODE);
122	    assert.ok(tag);
123	    assert.equal(tag!.source, 'exit-code');
124	  });
125	
126	  it('returns null for exit code 0', () => {
127	    assert.equal(detectRateLimitFromExitCode(0), null);
128	  });
129	
130	  it('returns null for generic non-zero exit codes', () => {
131	    assert.equal(detectRateLimitFromExitCode(1), null);
132	    assert.equal(detectRateLimitFromExitCode(137), null);
133	  });
134	});
135	
136	// ── parseStreamJsonMessage cascade integration ──────────────────────
137	
138	describe('parseStreamJsonMessage() rate-limit accumulation', () => {
139	  it('writes a terminationTag on the accumulator when it sees a rate-limit subtype', () => {
140	    const acc = freshAcc();
141	    parseStreamJsonMessage({ type: 'result', subtype: 'rate_limit_error' }, acc);
142	    assert.ok(acc.terminationTag);
143	    assert.equal(acc.terminationTag!.kind, 'rate-limit');
144	  });
145	
146	  it('is first-wins — a later success does not clear the tag', () => {
147	    const acc = freshAcc();
148	    parseStreamJsonMessage({ is_error: true, error: '429 rate limit' }, acc);
149	    parseStreamJsonMessage({
150	      type: 'assistant',
151	      message: { content: [{ type: 'text', text: 'after' }] },
152	    }, acc);
153	    assert.ok(acc.terminationTag);
154	    assert.equal(acc.terminationTag!.source, 'ndjson-result');
155	  });
156	
157	  it('leaves terminationTag undefined on an ordinary happy-path transcript', () => {
158	    const acc = freshAcc();
159	    parseStreamJsonMessage({
160	      type: 'assistant',
161	      message: { content: [{ type: 'text', text: 'Done' }] },
